ee:message.ee:set-payload:
%dw 2.0 output application/json
var users = vars.users var posts = vars.posts
--- users map (u) -> { companyId: u.id, companyName: u.name, phone: u.phone, website: u.website, employees: posts filter ($.userId == u.id) map (p) -> { id: p.id, title: p.title, description: p.body } }

%dw 2.0
output application/java

var companies = payload

---
companies flatMap (c) ->

[
{
	method: "PATCH",
	url: "/services/data/v60.0/sobjects/Account/External_Id__c/" ++ (c.companyId as String),
	referenceId: "refAccount" ++ (c.companyId as String),
	body: {
		Name: c.companyName,
		Phone: c.phone,
		Website: c.website
	}
}
]

++
(
c.employees map (e) -> {
	method: "PATCH",
	url: "/services/data/v60.0/sobjects/Contact/External_Id__c/" ++ (e.id as String),
	referenceId: "refContact" ++ (e.id as String),
	body: {
		LastName: e.title,
		Description: e.description,
		AccountId: "@{refAccount" ++ (c.companyId as String) ++ ".id}"
	}
}
)
